import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { RequesterDashboard } from './requester-dashboard'
import { DesignerDashboard } from './designer-dashboard'
import { AdminDashboard } from './admin-dashboard'

export default async function DashboardPage() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) redirect('/login')

  const { data: profile } = await supabase.from('profiles').select('*').eq('id', user.id).single()
  if (!profile) redirect('/login')

  const { data: requests } = await supabase
    .from('design_requests')
    .select(`*, channel:channels(id,name,slug), requester:profiles!design_requests_requester_id_fkey(id,name), designer:profiles!design_requests_designer_id_fkey(id,name)`)
    .order('created_at', { ascending: false })
    .limit(100)

  if (profile.role === 'designer') {
    return <DesignerDashboard requests={requests ?? []} profile={profile} />
  }
  if (profile.role === 'admin') {
    const { data: allProfiles } = await supabase.from('profiles').select('*')
    return <AdminDashboard requests={requests ?? []} profiles={allProfiles ?? []} profile={profile} />
  }
  return <RequesterDashboard requests={requests ?? []} profile={profile} />
}
